import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useGoogleLogin } from '@react-oauth/google';
import Navbar from '../components/Navbar';
import fitnessBg from '../assets/V.png';
import axios from 'axios';

export default function LoginPage() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);
  const [serverError, setServerError] = useState('');

  const validate = () => {
    const errs = {};
    if (!form.email) errs.email = 'Email is required';
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) errs.email = 'Enter a valid email';
    if (!form.password) errs.password = 'Password is required';
    return errs;
  };

  const handleChange = e => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
    if (errors[e.target.name]) setErrors(prev => ({ ...prev, [e.target.name]: '' }));
    if (serverError) setServerError('');
  };

  const handleSubmit = async e => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }
    setLoading(true);
    try {
      const res = await axios.post('http://localhost:8080/api/auth/login', form);
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data));
      navigate('/dashboard');
    } catch (err) {
      setServerError(err.response?.data?.message || 'Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (tokenResponse) => {
    setGoogleLoading(true);
    setServerError('');
    try {
      const res = await axios.post('http://localhost:8080/api/auth/google', {
        credential: tokenResponse.access_token,
      });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data));
      navigate('/dashboard');
    } catch (err) {
      setServerError('Google login failed. Please try again.');
    } finally {
      setGoogleLoading(false);
    }
  };

  const googleLogin = useGoogleLogin({
    onSuccess: handleGoogleSuccess,
    onError: () => setServerError('Google login was cancelled or failed.'),
  });

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', position: 'relative' }}>

      {/* Background image */}
      <div style={{
        position: 'fixed', inset: 0,
        backgroundImage: `url(${fitnessBg})`,
        backgroundSize: 'cover', backgroundPosition: 'center',
        zIndex: 0,
      }} />

      {/* Blur + dim overlay */}
      <div style={{
        position: 'fixed', inset: 0,
        backdropFilter: 'blur(3px)', WebkitBackdropFilter: 'blur(3px)',
        background: 'rgba(240, 240, 216, 0.25)',
        zIndex: 1,
      }} />

      <div style={{ position: 'relative', zIndex: 10 }}>
        <Navbar />
      </div>

      <div style={{
        flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
        padding: '100px 24px 48px', position: 'relative', zIndex: 5,
      }}>
        <div style={{ width: '100%', maxWidth: '420px', animation: 'fadeUp 0.5s ease forwards' }}>

          <div style={{ textAlign: 'center', marginBottom: '28px' }}>
            <h1 style={{
              fontFamily: 'var(--font-display)', fontSize: '32px',
              letterSpacing: '-0.025em', marginBottom: '6px', color: 'var(--ink)',
            }}>Welcome back</h1>
            <p style={{ fontSize: '14px', color: 'var(--ink-muted)' }}>
              Log in to your V-Fit account
            </p>
          </div>

          <div style={{
            background: 'rgba(245, 245, 225, 0.95)',
            backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)',
            borderRadius: 'var(--radius-lg)',
            border: '1px solid rgba(44,44,26,0.16)',
            padding: '32px',
            boxShadow: '0 12px 48px rgba(44,44,26,0.18)',
          }}>

            {serverError && (
              <div style={{
                background: 'rgba(192,57,43,0.1)', border: '1px solid rgba(192,57,43,0.25)',
                borderRadius: 'var(--radius-md)', padding: '12px 16px',
                marginBottom: '20px', fontSize: '14px', color: 'var(--accent)',
              }}>
                {serverError}
              </div>
            )}

            {/* Email/password form */}
            <form onSubmit={handleSubmit} noValidate>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '18px', marginBottom: '24px' }}>
                <div className="form-group">
                  <label className="form-label">Email address</label>
                  <input
                    type="email" name="email"
                    className={`form-input ${errors.email ? 'error' : ''}`}
                    placeholder="you@example.com"
                    value={form.email} onChange={handleChange} autoComplete="email"
                  />
                  {errors.email && <span className="form-error">{errors.email}</span>}
                </div>

                <div className="form-group">
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <label className="form-label">Password</label>
                    <a href="#forgot" style={{ fontSize: '12px', color: 'var(--green)' }}>Forgot password?</a>
                  </div>
                  <input
                    type="password" name="password"
                    className={`form-input ${errors.password ? 'error' : ''}`}
                    placeholder="Enter your password"
                    value={form.password} onChange={handleChange} autoComplete="current-password"
                  />
                  {errors.password && <span className="form-error">{errors.password}</span>}
                </div>
              </div>

              <button
                type="submit" className="btn btn-green" disabled={loading}
                style={{ width: '100%', justifyContent: 'center', padding: '13px', fontSize: '15px' }}
              >
                {loading ? (
                  <span style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ animation: 'spin 0.8s linear infinite' }}>
                      <circle cx="8" cy="8" r="6" stroke="rgba(255,255,255,0.3)" strokeWidth="2"/>
                      <path d="M8 2C11.3 2 14 4.7 14 8" stroke="white" strokeWidth="2" strokeLinecap="round"/>
                    </svg>
                    Logging in…
                  </span>
                ) : 'Log in'}
              </button>
            </form>

            {/* Divider */}
            <div className="divider" style={{ margin: '20px 0' }}>or</div>

            {/* Google button */}
            <button
              onClick={() => googleLogin()}
              disabled={googleLoading}
              style={{
                width: '100%', display: 'flex', alignItems: 'center',
                justifyContent: 'center', gap: '10px', padding: '12px',
                background: 'white', border: '1.5px solid rgba(44,44,26,0.2)',
                borderRadius: 'var(--radius-full)', fontSize: '14px',
                fontWeight: '500', color: 'var(--ink)', cursor: 'pointer',
                fontFamily: 'var(--font-body)',
                transition: 'all 0.2s ease',
              }}
              onMouseEnter={e => e.currentTarget.style.boxShadow = '0 2px 8px rgba(44,44,26,0.12)'}
              onMouseLeave={e => e.currentTarget.style.boxShadow = 'none'}
            >
              {googleLoading ? (
                <svg width="18" height="18" viewBox="0 0 16 16" fill="none" style={{ animation: 'spin 0.8s linear infinite' }}>
                  <circle cx="8" cy="8" r="6" stroke="#ccc" strokeWidth="2"/>
                  <path d="M8 2C11.3 2 14 4.7 14 8" stroke="#4285F4" strokeWidth="2" strokeLinecap="round"/>
                </svg>
              ) : (
                <svg width="18" height="18" viewBox="0 0 18 18">
                  <path d="M17.64 9.2c0-.637-.057-1.251-.164-1.84H9v3.481h4.844c-.209 1.125-.843 2.078-1.796 2.717v2.258h2.908c1.702-1.567 2.684-3.874 2.684-6.615z" fill="#4285F4"/>
                  <path d="M9 18c2.43 0 4.467-.806 5.956-2.184l-2.908-2.258c-.806.54-1.837.86-3.048.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332C2.438 15.983 5.482 18 9 18z" fill="#34A853"/>
                  <path d="M3.964 10.707c-.18-.54-.282-1.117-.282-1.707s.102-1.167.282-1.707V4.961H.957C.347 6.175 0 7.55 0 9s.348 2.825.957 4.039l3.007-2.332z" fill="#FBBC05"/>
                  <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0 5.482 0 2.438 2.017.957 4.961L3.964 7.293C4.672 5.166 6.656 3.58 9 3.58z" fill="#EA4335"/>
                </svg>
              )}
              {googleLoading ? 'Signing in with Google…' : 'Continue with Google'}
            </button>
          </div>

          <p style={{ textAlign: 'center', marginTop: '24px', fontSize: '14px', color: 'var(--ink-muted)' }}>
            Don't have an account?{' '}
            <Link to="/register" style={{ color: 'var(--green)', fontWeight: '500' }}>Sign up free</Link>
          </p>
        </div>
      </div>

      <style>{`
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
}
